import { Component, Input, OnInit } from '@angular/core';
import { LoaderService } from './loader.service';

@Component({
  selector: 'lib-hash-loader',
  templateUrl: './hash-loader.component.html',
  styleUrls: ['./hash-loader.component.scss']
})
export class HashLoaderComponent implements OnInit {

  isLoading:boolean = false;
  @Input() topOffSet:any;

  heightStyle :any;

  constructor(private loaderService: LoaderService) { }

  ngOnInit(): void {
    if(this.topOffSet) this.heightStyle = `height: calc(100vh - ${this.topOffSet})`;
    else this.heightStyle = 'height: 100vh';
    this.loaderService.isLoading.subscribe((status:boolean) => {
      this.isLoading = status;
    });
  }

}
